use super::body::presentation_html_section_body;
use crate::section::style::presentation_html_style;
use axum::{extract::State, response::Html};
use injection::cross_cutting::InjectedServices;

pub async fn presentation_html_section_page(
    State(services): State<InjectedServices>,
) -> Html<String> {
    Html(
        r##"
    <!doctype html>
    <html lang="en">
        <head>
        <meta charset="UTF-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1.0" />
        <meta http-equiv="X-UA-Compatible" content="ie=edge" />
        <link rel="icon" href="/preto_no_branco.ico" type="image/x-icon">
        <title>Lince</title>
        "##
        .to_string()
            + presentation_html_style(services.clone()).await.as_str()
            + datastar_1_0_0rc8()
            + "</head>"
            + presentation_html_section_body(services).await.as_str()
            + "</html>",
    )
}
